class Solution {
public:
    bool checkRecord(string s) {
        int absentCount = 0;
        int lateCount = 0;
        for (int i = 0; i < s.length(); i++) {
            if (s[i] == 'A') {
                absentCount++;
            } else if (s[i] == 'L') {
                lateCount++;
                if (lateCount == 3) {
                    return false;
                }
            } else {
                lateCount = 0;
            }
        }
        return absentCount < 2;
    }
};
```
